//! Generates src/generated_consts.rs from the parsed Config.

use super::config_types::Config;
use super::feature_graph::{
    feature_enabled, feature_primary_group, load_feature_graph_from_manifest,
};

/// Produces the full content of generated_consts.rs.
pub fn emit_all_consts(config: &Config) -> String {
    let mut c = String::with_capacity(16 * 1024);

    c.push_str("//! AUTO-GENERATED CONFIGURATION - DO NOT EDIT\n");
    c.push_str(
        "//! Generated by build.rs from Cargo.toml [package.metadata.aethercore.config]\n\n",
    );

    // ── Meta ──────────────────────────────────────────────────────────────
    c.push_str(&format!(
        "pub const META_PROFILE: &str = \"{}\";\n",
        config.meta.profile
    ));
    c.push_str(&format!(
        "pub const META_VERSION: &str = \"{}\";\n",
        config.meta.version
    ));

    // ── Kernel ────────────────────────────────────────────────────────────
    c.push_str(&format!(
        "pub const TIME_SLICE_NS: u64 = {};\n",
        config.kernel.time_slice_ns
    ));
    c.push_str(&format!(
        "pub const STACK_SIZE_PAGES: usize = {};\n",
        config.kernel.stack_size_pages
    ));
    c.push_str(&format!(
        "pub const KERNEL_MAX_CPUS: usize = {};\n",
        config.kernel.max_cpus
    ));
    c.push_str(&format!(
        "pub const INTERRUPT_STACK_SIZE_PAGES: usize = {};\n",
        config.kernel.interrupt_stack_size_pages
    ));
    c.push_str(&format!(
        "pub const TARGET_ARCH: &str = \"{}\";\n",
        config.kernel.arch
    ));

    // ── Boot ──────────────────────────────────────────────────────────────
    c.push_str(&format!(
        "pub const BOOT_CMDLINE_PARSE: bool = {};\n",
        config.boot.cmdline_parse
    ));
    c.push_str(&format!(
        "pub const BOOT_SPLASH: bool = {};\n",
        config.boot.splash_screen
    ));
    c.push_str(&format!(
        "pub const BOOT_QUIET: bool = {};\n",
        config.boot.quiet_boot
    ));

    // ── Library ───────────────────────────────────────────────────────────
    emit_library(&mut c, config);

    // ── Core toggles ──────────────────────────────────────────────────────
    emit_core(&mut c, config);

    // ── Memory ────────────────────────────────────────────────────────────
    emit_memory(&mut c, config);

    // ── Scheduler ─────────────────────────────────────────────────────────
    emit_scheduler(&mut c, config);

    // ── Dispatcher ────────────────────────────────────────────────────────
    c.push_str(&format!(
        "pub const DISPATCHER_BUFFER_SIZE: usize = {};\n",
        config.dispatcher.buffer_size
    ));
    c.push_str(&format!(
        "pub const DISPATCHER_VECTOR_ALIGN: usize = {};\n",
        config.dispatcher.vector_table_align
    ));

    // ── IPC ───────────────────────────────────────────────────────────────
    emit_ipc(&mut c, config);

    // ── Security ──────────────────────────────────────────────────────────
    emit_security(&mut c, config);

    // ── Telemetry ─────────────────────────────────────────────────────────
    emit_telemetry(&mut c, config);

    // ── Linux Compat ──────────────────────────────────────────────────────
    emit_linux_compat(&mut c, config);

    // ── VFS ───────────────────────────────────────────────────────────────
    emit_vfs(&mut c, config);

    // ── Network ───────────────────────────────────────────────────────────
    emit_network(&mut c, config);

    // ── Drivers ───────────────────────────────────────────────────────────
    emit_drivers(&mut c, config);

    // ── Governor ──────────────────────────────────────────────────────────
    emit_governor(&mut c, config);

    // ── Linux OS Info ─────────────────────────────────────────────────────
    c.push_str(&format!(
        "pub const LINUX_RELEASE_STR: &str = \"{}\";\n",
        config.linux_os.release
    ));
    c.push_str(&format!(
        "pub const LINUX_VERSION_STR: &str = \"{}\";\n",
        config.linux_os.version
    ));

    // ── AArch64 ───────────────────────────────────────────────────────────
    emit_aarch64(&mut c, config);

    // ── Lottery Scheduler ─────────────────────────────────────────────────
    emit_lottery(&mut c, config);

    // ── Log level numeric ─────────────────────────────────────────────────
    let log_level_num = match config.telemetry.log_level.as_str() {
        "Error" => 1,
        "Warn" => 2,
        "Info" => 3,
        "Debug" => 4,
        "Trace" => 5,
        _ => 3,
    };
    c.push_str(&format!(
        "pub const LOG_LEVEL_NUM: u8 = {};\n",
        log_level_num
    ));

    // ── Feature catalog ───────────────────────────────────────────────────
    emit_feature_catalog(&mut c);

    c
}

