fn emit_scheduler(c: &mut String, config: &Config) {
    let s = &config.scheduler;
    c.push_str(&format!(
        "pub const SCHED_PRIORITY_LEVELS: usize = {};\n",
        s.priority_levels
    ));

    if let Some(rr) = &s.round_robin {
        c.push_str(&format!(
            "pub const SCHED_RR_MAX_TASKS: usize = {};\n",
            rr.max_tasks
        ));
        c.push_str(&format!(
            "pub const SCHED_RR_DEFAULT_SLICE_NS: u64 = {};\n",
            rr.default_slice_ns
        ));
    }

    if let Some(cfs) = &s.cfs {
        c.push_str(&format!(
            "pub const SCHED_CFS_MIN_GRANULARITY_NS: u64 = {};\n",
            cfs.min_granularity_ns
        ));
        c.push_str(&format!(
            "pub const SCHED_CFS_LATENCY_TARGET_NS: u64 = {};\n",
            cfs.latency_target_ns
        ));
    }

    if let Some(edf) = &s.edf {
        c.push_str(&format!(
            "pub const SCHED_EDF_MAX_DEADLINES: usize = {};\n",
            edf.max_deadlines
        ));
        c.push_str(&format!(
            "pub const SCHED_EDF_ENFORCE_DEADLINE: bool = {};\n",
            edf.enforce_deadline
        ));
        c.push_str(&format!(
            "pub const SCHED_EDF_DEFAULT_RELATIVE_DEADLINE_NS: u64 = {};\n",
            edf.default_relative_deadline_ns
        ));
    } else {
        c.push_str("pub const SCHED_EDF_MAX_DEADLINES: usize = 128;\n");
        c.push_str("pub const SCHED_EDF_ENFORCE_DEADLINE: bool = true;\n");
        c.push_str("pub const SCHED_EDF_DEFAULT_RELATIVE_DEADLINE_NS: u64 = 8000000;\n");
    }

    if let Some(mlfq) = &s.mlfq {
        c.push_str(&format!(
            "pub const SCHED_MLFQ_NUM_QUEUES: usize = {};\n",
            mlfq.num_queues
        ));
        c.push_str(&format!(
            "pub const SCHED_MLFQ_BASE_SLICE_NS: u64 = {};\n",
            mlfq.base_slice_ns
        ));
        c.push_str(&format!(
            "pub const SCHED_MLFQ_BOOST_INTERVAL_TICKS: u64 = {};\n",
            mlfq.boost_interval_ticks
        ));
        c.push_str(&format!(
            "pub const SCHED_MLFQ_DEMOTE_ON_SLICE_EXHAUSTION: bool = {};\n",
            mlfq.demote_on_slice_exhaustion
        ));
    } else {
        c.push_str("pub const SCHED_MLFQ_NUM_QUEUES: usize = 4;\n");
        c.push_str("pub const SCHED_MLFQ_BASE_SLICE_NS: u64 = 1000000;\n");
        c.push_str("pub const SCHED_MLFQ_BOOST_INTERVAL_TICKS: u64 = 250;\n");
        c.push_str("pub const SCHED_MLFQ_DEMOTE_ON_SLICE_EXHAUSTION: bool = true;\n");
    }

    if let Some(rt) = &s.rt {
        c.push_str(&format!(
            "pub const SCHED_RT_ENABLE_GROUP_RESERVATION: bool = {};\n",
            rt.enable_group_reservation
        ));
        c.push_str(&format!(
            "pub const SCHED_RT_PERIOD_NS: u64 = {};\n",
            rt.period_ns
        ));
        c.push_str(&format!(
            "pub const SCHED_RT_TOTAL_UTILIZATION_CAP_PERCENT: u8 = {};\n",
            rt.total_utilization_cap_percent
        ));
        c.push_str(&format!(
            "pub const SCHED_RT_MAX_GROUPS: usize = {};\n",
            rt.max_groups
        ));
    } else {
        c.push_str("pub const SCHED_RT_ENABLE_GROUP_RESERVATION: bool = false;\n");
        c.push_str("pub const SCHED_RT_PERIOD_NS: u64 = 100000000;\n");
        c.push_str("pub const SCHED_RT_TOTAL_UTILIZATION_CAP_PERCENT: u8 = 80;\n");
        c.push_str("pub const SCHED_RT_MAX_GROUPS: usize = 8;\n");
    }

    // Additional constants needed by source
    c.push_str("pub const WRR_MAX_WEIGHT: usize = 2000;\n");
    c.push_str("pub const FIFO_ALLOW_PREEMPTION: bool = false;\n");
    c.push_str(&format!(
        "pub const RR_MAX_TASKS: usize = {};\n",
        s.round_robin
            .as_ref()
            .map(|rr| rr.max_tasks)
            .unwrap_or(1024)
    ));
}

