fn emit_aarch64(c: &mut String, config: &Config) {
    let a = &config.aarch64;
    let ecam_bases = if a.pci_ecam_bases.is_empty() {
        vec![0x1000_0000u64, 0x3F00_0000u64]
    } else {
        a.pci_ecam_bases.clone()
    };
    let ecam_list = ecam_bases
        .iter()
        .map(|v| format!("0x{:x}u64", v))
        .collect::<Vec<_>>()
        .join(", ");
    c.push_str(&format!(
        "pub const AARCH64_PCI_ECAM_BASES: [u64; {}] = [{}];\n",
        ecam_bases.len(),
        ecam_list
    ));
    c.push_str(&format!(
        "pub const AARCH64_PCI_SCAN_STOP_ON_FIRST_HIT: bool = {};\n",
        a.pci_scan_stop_on_first_hit
    ));
    c.push_str(&format!(
        "pub const AARCH64_PCI_MAX_BUS: u16 = {};\n",
        a.pci_max_bus
    ));
    c.push_str(&format!(
        "pub const AARCH64_PCI_MAX_DEVICE: u8 = {};\n",
        a.pci_max_device
    ));
    c.push_str(&format!(
        "pub const AARCH64_PCI_MAX_FUNCTION: u8 = {};\n",
        a.pci_max_function
    ));
    c.push_str(&format!(
        "pub const AARCH64_SMP_BOOT_TIMEOUT_SPINS: u64 = {};\n",
        a.smp_boot_timeout_spins
    ));
    c.push_str(&format!(
        "pub const AARCH64_EXCEPTION_KILL_USER_SYNC: bool = {};\n",
        a.exception_kill_user_sync
    ));
    c.push_str(&format!(
        "pub const AARCH64_EXCEPTION_KILL_USER_ASYNC: bool = {};\n",
        a.exception_kill_user_async
    ));
    c.push_str(&format!(
        "pub const AARCH64_EXCEPTION_PANIC_ON_KERNEL_SYNC: bool = {};\n",
        a.exception_panic_on_kernel_sync
    ));
    c.push_str(&format!(
        "pub const AARCH64_EXCEPTION_PANIC_ON_KERNEL_ASYNC: bool = {};\n",
        a.exception_panic_on_kernel_async
    ));
    c.push_str(&format!(
        "pub const AARCH64_IRQ_STORM_WINDOW_TICKS: u64 = {};\n",
        a.irq_storm_window_ticks
    ));
    c.push_str(&format!(
        "pub const AARCH64_IRQ_STORM_THRESHOLD: u64 = {};\n",
        a.irq_storm_threshold
    ));
    c.push_str(&format!(
        "pub const AARCH64_IRQ_STORM_LOG_EVERY: u64 = {};\n",
        a.irq_storm_log_every
    ));
    c.push_str(&format!(
        "pub const AARCH64_TIMER_REARM_MIN_TICKS: u64 = {};\n",
        a.timer_rearm_min_ticks
    ));
    c.push_str(&format!(
        "pub const AARCH64_TIMER_REARM_MAX_TICKS: u64 = {};\n",
        a.timer_rearm_max_ticks
    ));
    c.push_str(&format!(
        "pub const AARCH64_TIMER_JITTER_TOLERANCE_TICKS: u64 = {};\n",
        a.timer_jitter_tolerance_ticks
    ));
    c.push_str(&format!(
        "pub const AARCH64_GIC_CPU_PRIORITY_MASK: u32 = {};\n",
        a.gic_cpu_priority_mask
    ));
    c.push_str(&format!(
        "pub const AARCH64_IRQ_RATE_TRACK_LIMIT: usize = {};\n",
        a.irq_rate_track_limit
    ));
    c.push_str(&format!(
        "pub const AARCH64_IRQ_PER_LINE_STORM_THRESHOLD: u64 = {};\n",
        a.irq_per_line_storm_threshold
    ));
    c.push_str(&format!(
        "pub const AARCH64_IRQ_PER_LINE_LOG_EVERY: u64 = {};\n",
        a.irq_per_line_log_every
    ));
    c.push_str(&format!(
        "pub const AARCH64_TLB_SHOOTDOWN_TIMEOUT_SPINS: usize = {};\n",
        a.tlb_shootdown_timeout_spins.max(1)
    ));

    let smp_known_mpidrs = if a.smp_known_mpidrs.is_empty() {
        vec![0x0000_0001u64, 0x0000_0002u64, 0x0000_0003u64]
    } else {
        a.smp_known_mpidrs.clone()
    };
    let smp_list = smp_known_mpidrs
        .iter()
        .map(|v| format!("0x{:x}u64", v))
        .collect::<Vec<_>>()
        .join(", ");
    c.push_str(&format!(
        "pub const AARCH64_SMP_KNOWN_MPIDRS: [u64; {}] = [{}];\n",
        smp_known_mpidrs.len(),
        smp_list
    ));
}

