fn emit_feature_catalog(c: &mut String) {
    let feature_graph = load_feature_graph_from_manifest();
    let feature_names: Vec<String> = feature_graph.keys().cloned().collect();
    let count = feature_names.len();

    let names_joined = feature_names
        .iter()
        .map(|n| format!("\"{}\"", n))
        .collect::<Vec<_>>()
        .join(", ");
    let enabled_joined = feature_names
        .iter()
        .map(|n| if feature_enabled(n) { "true" } else { "false" }.to_string())
        .collect::<Vec<_>>()
        .join(", ");
    let primary_group_joined = feature_names
        .iter()
        .map(|n| format!("\"{}\"", feature_primary_group(n, &feature_graph)))
        .collect::<Vec<_>>()
        .join(", ");

    c.push_str(&format!(
        "pub const CARGO_FEATURE_COUNT: usize = {};\n",
        count
    ));
    c.push_str(&format!(
        "pub const CARGO_FEATURE_NAMES: [&str; {}] = [{}];\n",
        count, names_joined
    ));
    c.push_str(&format!(
        "pub const CARGO_FEATURE_ENABLED: [bool; {}] = [{}];\n",
        count, enabled_joined
    ));
    c.push_str(&format!(
        "pub const CARGO_FEATURE_PRIMARY_GROUP: [&str; {}] = [{}];\n",
        count, primary_group_joined
    ));
}
